	import sailpoint.api.SailPointFactory;
	import sailpoint.api.SailPointContext;
	import sailpoint.api.IdentityService;
	import sailpoint.api.Provisioner;
	import sailpoint.object.ProvisioningPlan.AttributeRequest;
	import sailpoint.object.Application;
	import sailpoint.object.Filter;
	import sailpoint.object.Identity;
	import sailpoint.object.IdentityEntitlement;
	import sailpoint.object.Link;
	import sailpoint.object.ProvisioningPlan.AccountRequest;
	import sailpoint.object.ProvisioningPlan.Operation;
	import sailpoint.object.QueryOptions;
	import sailpoint.tools.Util;
	import sailpoint.tools.Message;
	import sailpoint.tools.GeneralException;

	import java.util.Date;
	import java.util.List;


    import org.apache.commons.logging.Log;
    import org.apache.commons.logging.LogFactory;

    private static Log rlogger = LogFactory.getLog("rule.SP.Rehire.RulesLibrary");
	
	public boolean isGroupExisted(String identityName,String entValue,String appName){
		
		
		QueryOptions qo=new QueryOptions();
		Filter f1=Filter.eq("application.name", appName);
		Filter f2=Filter.eq("identity.name", identityName);
		Filter f3=Filter.eq("value", entValue);

		Filter filter=Filter.and(f1,f2,f3);
		IdentityEntitlement idObj = context.getUniqueObject(IdentityEntitlement.class, filter); 

		if(idObj!=null){
			return true;
		}
		return false;
	}

	public boolean isAppExist(String identityName,String appName){
		
		Filter filter=Filter.and(Filter.eq("links.application.name",appName),Filter.eq("name",identityName));
			
		Identity identity=context.getUniqueObject(Identity.class,filter);
		if(identity!=null){
			return true;
		}
		return false;
	}
	
	public String getNativeIdentity(Identity identity,String appName){
		String accountDN=null;
		IdentityService idSvc = new IdentityService(context);
		Application application = context.getObjectByName(Application.class, appName);		
		List links = idSvc.getLinks(identity,application);
		if(links.size() > 0){
			return links.get(0).getNativeIdentity();
		}
		
		return accountDN;	
	}
	public boolean getDuoCreated(Identity identity,String appName){		
		IdentityService idSvc = new IdentityService(context);
		Application application = context.getObjectByName(Application.class, appName);	
		Date date=new Date();		
		List links = idSvc.getLinks(identity,application);
		if(links.size() > 0){
			Link link=links.get(0);
			if(Util.getDaysDifference(date,link.getCreated())>45){
				return true;
			}
		}		
		return false;	
	}
